package model

import (
	"encoding/json"
	"fmt"
	"os"
	"os/exec"
	"path/filepath"
	"strings"
	"time"

	"github.com/charmbracelet/bubbles/textinput"
	tea "github.com/charmbracelet/bubbletea"

	"github.com/black-atom-industries/helm/internal/claude"
	"github.com/black-atom-industries/helm/internal/config"
	"github.com/black-atom-industries/helm/internal/git"
	"github.com/black-atom-industries/helm/internal/lib/fuzzy"
	"github.com/black-atom-industries/helm/internal/pi"
	"github.com/black-atom-industries/helm/internal/tmux"
	"github.com/black-atom-industries/helm/internal/ui"
)

// Mode represents the current UI mode
type Mode int

const (
	ModeNormal Mode = iota
	ModeConfirmKill
	ModeCreate
	ModePickDirectory
	ModeConfirmRemoveFolder
	ModeCloneChoice // Sub-menu: URL or My Repos
	ModeCloneRepo
	ModeCloneURL // Text input for arbitrary repo URL
	ModeBookmarks
	ModeCreatePath // Path input for creating session at arbitrary path
)

// String returns the display name for the mode (used in title bar)
func (m Mode) String() string {
	switch m {
	case ModeNormal:
		return "SESSIONS"
	case ModeBookmarks:
		return "BOOKMARKS"
	case ModePickDirectory:
		return "PROJECTS"
	case ModeCloneChoice, ModeCloneRepo, ModeCloneURL:
		return "DOWNLOADS"
	case ModeCreate:
		return "NEW"
	case ModeCreatePath:
		return "PATH"
	case ModeConfirmKill:
		return "KILL"
	case ModeConfirmRemoveFolder:
		return "REMOVE"
	default:
		return "SESSIONS"
	}
}

// ItemType represents the type of item in the flattened list
type ItemType int

const (
	ItemTypeSession ItemType = iota
	ItemTypeWindow
	ItemTypePane
)

// Item represents a session, window, or pane in the flattened list
type Item struct {
	Type         ItemType
	SessionIndex int  // Index in the sessions slice
	WindowIndex  int  // Index in the session's windows slice (for windows and panes)
	PaneIndex    int  // Index in the window's panes slice (for panes only)
	IsSelf       bool // True if this item belongs to the current/self session
}

// Model is the main application state
type Model struct {
	sessions          []tmux.Session
	selfSession       *tmux.Session // The current/self session (pinned at top)
	claudeStatuses    map[string]claude.Status
	piStatuses        map[string]pi.Status
	gitStatuses       map[string]git.Status
	currentSession    string
	cursor            int
	items             []Item // Flattened list of visible items
	mode              Mode
	message           string
	messageIsError    bool
	input             textinput.Model
	killTarget        string // Name of session/window being killed
	removeTarget      string // Full path of folder being removed
	config            config.Config
	maxNameWidth      int    // For column alignment
	maxGitStatusWidth int    // For git status column alignment
	filter            string // Current filter text for fuzzy matching

	// Directory picker state (uses ScrollList for cursor/scroll/filter)
	projectList        *ui.ScrollList[string]
	returnToBookmarks  bool   // True if we should return to bookmarks mode after project picker
	pendingSessionName string // Session name pending directory selection (for create-from-filter flow)

	// Path input state (for ModeCreatePath)
	pathInput       textinput.Model // Text input for path entry
	pathCompletions []string        // Available path completions

	// Scroll state
	scrollOffset int // Scroll offset for session list

	// Window size
	width  int
	height int

	// Animation state
	animationFrame int

	// Clone mode state
	cloneChoiceCursor   int // 0 = Enter URL, 1 = My repos
	cloneList           *ui.ScrollList[string]
	cloneBasePath       string // From config.ProjectDirs
	cloneLoading        bool   // True while fetching repos
	cloneError          string // Error message if fetch/clone fails
	cloneCloning        bool   // True while cloning
	cloneCloningRepo    string // Repo being cloned
	cloneSuccess        bool   // True when clone completed, awaiting confirmation
	cloneSuccessPath    string // Path of cloned repo (for layout)
	cloneSuccessSession string // Session name to switch to
	clonePendingFilter  string // Filter to apply once repos are loaded

	// Bookmarks mode state (uses ScrollList for cursor/scroll/filter)
	bookmarkList     *ui.ScrollList[config.Bookmark]
	bookmarkExpanded map[string]bool // Tracks which bookmarks are expanded (by path)

	// Loading state
	sessionsLoaded bool // True after sessions have been loaded at least once

	// Git status loading state
	gitStatusPending     map[string]bool // Sessions still being fetched (by name)
	gitStatusShowLoading bool            // True after 500ms delay if still loading
}

// New creates a new Model
// ParseInitialView maps a CLI flag value to a Mode.
// Returns ModeNormal for empty or unrecognized values.
func ParseInitialView(view string) Mode {
	switch strings.ToLower(view) {
	case "bookmarks":
		return ModeBookmarks
	case "projects":
		return ModePickDirectory
	case "clone":
		return ModeCloneChoice
	default:
		return ModeNormal
	}
}

func New(currentSession string, cfg config.Config, initialView string) Model {
	ti := textinput.New()
	ti.Prompt = "" // We handle the prompt in RenderPrompt
	ti.CharLimit = 50

	// Path input for ModeCreatePath
	pathInput := textinput.New()
	pathInput.Prompt = ""
	pathInput.CharLimit = 256

	// Create project list with filter function that matches on display path
	projectList := ui.NewScrollList(func(fullPath string, filter string) bool {
		parts := strings.Split(fullPath, string(filepath.Separator))
		depth := cfg.ProjectDepth
		if depth > len(parts) {
			depth = len(parts)
		}
		displayPath := strings.Join(parts[len(parts)-depth:], "/")
		return fuzzy.Match(displayPath, filter)
	})

	// Create clone list with filter function that matches on repo name
	cloneList := ui.NewScrollList(func(repo string, filter string) bool {
		return fuzzy.Match(repo, filter)
	})

	// Create bookmark list with filter function that matches on path basename
	bookmarkList := ui.NewScrollList(func(b config.Bookmark, filter string) bool {
		name := filepath.Base(b.Path)
		return fuzzy.Match(name, filter) || fuzzy.Match(b.Path, filter)
	})

	m := Model{
		currentSession:   currentSession,
		mode:             ParseInitialView(initialView),
		input:            ti,
		pathInput:        pathInput,
		config:           cfg,
		projectList:      projectList,
		cloneList:        cloneList,
		bookmarkList:     bookmarkList,
		bookmarkExpanded: make(map[string]bool),
	}

	// Populate data for non-default initial views
	switch m.mode {
	case ModePickDirectory:
		m.projectList.SetItems(m.scanProjectDirectories())
	case ModeBookmarks:
		m.bookmarkList.SetItems(cfg.Bookmarks)
	}

	// Load cached sessions for instant startup
	if cached := m.loadSessionCache(); cached != nil {
		m.sessions = cached
		m.sessionsLoaded = true
		m.calculateColumnWidths()
		// Reserve git status column to prevent layout shift when statuses load
		if cfg.GitStatusEnabled {
			m.maxGitStatusWidth = ui.GitStatusColumnWidth
		}
		m.rebuildItems()
	}

	return m
}

// Init implements tea.Model
func (m Model) Init() tea.Cmd {
	return tea.Batch(m.loadSessions, animationTick())
}

// loadSessions fetches sessions from tmux
func (m Model) loadSessions() tea.Msg {
	sessions, err := tmux.ListSessions(m.currentSession)
	if err != nil {
		return errMsg{err}
	}

	// Fetch self session activity
	var selfSession *tmux.Session
	if m.currentSession != "" {
		activity, err := tmux.GetSessionActivity(m.currentSession)
		if err == nil {
			selfSession = &tmux.Session{
				Name:         m.currentSession,
				LastActivity: activity,
			}
		}
	}

	return sessionsMsg{sessions: sessions, selfSession: selfSession}
}

type sessionsMsg struct {
	sessions    []tmux.Session
	selfSession *tmux.Session
}

type errMsg struct {
	err error
}

type clearMessageMsg struct{}

type animationTickMsg struct{}

// gitStatusSingleMsg is sent when a single session's git status is ready
type gitStatusSingleMsg struct {
	sessionName string
	status      git.Status
	hasStatus   bool // true if status should be shown (repo with changes)
}

// gitStatusLoadingMsg is sent after 500ms to show loading indicator
type gitStatusLoadingMsg struct{}

// clearMessageAfter returns a command that clears the message after a delay
func clearMessageAfter(d time.Duration) tea.Cmd {
	return tea.Tick(d, func(time.Time) tea.Msg {
		return clearMessageMsg{}
	})
}

// animationTick returns a command that ticks the animation
func animationTick() tea.Cmd {
	return tea.Tick(300*time.Millisecond, func(time.Time) tea.Msg {
		return animationTickMsg{}
	})
}

// Update implements tea.Model
func (m Model) Update(msg tea.Msg) (tea.Model, tea.Cmd) {
	switch msg := msg.(type) {
	case sessionsMsg:
		m.sessions = msg.sessions
		m.selfSession = msg.selfSession
		m.sessionsLoaded = true
		m.saveSessionCache() // Cache for instant startup next time
		m.loadClaudeStatuses()
		m.loadPiStatuses()
		// Initialize git statuses map (will be populated async)
		if m.gitStatuses == nil {
			m.gitStatuses = make(map[string]git.Status)
		}
		// Reserve git status column width to prevent layout shift
		if m.config.GitStatusEnabled {
			m.maxGitStatusWidth = ui.GitStatusColumnWidth
		}
		m.calculateColumnWidths()
		m.rebuildItems()
		// Place cursor on the first regular (non-self) session
		if m.selfSession != nil {
			for i, item := range m.items {
				if !item.IsSelf {
					m.cursor = i
					break
				}
			}
			m.updateScrollOffset()
		}
		if len(m.items) == 0 {
			m.message = "No sessions. Press C-n to create one."
		}
		// Fetch git statuses asynchronously to avoid blocking UI
		return m, m.fetchGitStatusesCmd()

	case errMsg:
		m.setError("Error: %v", msg.err)
		return m, nil

	case clearMessageMsg:
		m.message = ""
		m.messageIsError = false
		return m, nil

	case animationTickMsg:
		m.animationFrame = (m.animationFrame + 1) % 3
		return m, animationTick()

	case cloneReposLoadedMsg:
		m.cloneLoading = false
		m.cloneList.SetItems(msg.repos)
		if m.clonePendingFilter != "" {
			m.cloneList.SetFilter(m.clonePendingFilter)
			m.clonePendingFilter = ""
		}
		if len(msg.repos) == 0 {
			m.cloneError = "All repositories are already cloned!"
		}
		return m, nil

	case cloneErrorMsg:
		m.cloneLoading = false
		m.cloneCloning = false
		m.cloneError = msg.err.Error()
		return m, nil

	case cloneSuccessMsg:
		// Store success state and await confirmation
		m.cloneCloning = false
		m.cloneSuccess = true
		m.cloneSuccessPath = msg.repoPath
		m.cloneSuccessSession = msg.sessionName
		return m, nil

	case gitStatusSingleMsg:
		// Single git status loaded - update incrementally
		if msg.hasStatus {
			m.gitStatuses[msg.sessionName] = msg.status
		}
		delete(m.gitStatusPending, msg.sessionName)
		if len(m.gitStatusPending) == 0 {
			m.gitStatusShowLoading = false
		}
		return m, nil

	case gitStatusLoadingMsg:
		// 500ms elapsed - show loading indicator if still fetching
		if len(m.gitStatusPending) > 0 {
			m.gitStatusShowLoading = true
		}
		return m, nil

	case tea.WindowSizeMsg:
		m.width = msg.Width
		m.height = msg.Height
		return m, nil

	case tea.KeyMsg:
		return m.handleKey(msg)
	}

	// Handle text input updates in create mode
	if m.mode == ModeCreate {
		var cmd tea.Cmd
		m.input, cmd = m.input.Update(msg)
		return m, cmd
	}

	// Handle text input updates in create path mode
	if m.mode == ModeCreatePath {
		var cmd tea.Cmd
		m.pathInput, cmd = m.pathInput.Update(msg)
		return m, cmd
	}

	return m, nil
}

func (m *Model) handleKey(msg tea.KeyMsg) (tea.Model, tea.Cmd) {
	switch m.mode {
	case ModeNormal:
		return m.handleNormalMode(msg)
	case ModeConfirmKill:
		return m.handleConfirmKillMode(msg)
	case ModeCreate:
		return m.handleCreateMode(msg)
	case ModeCreatePath:
		return m.handleCreatePathMode(msg)
	case ModePickDirectory:
		return m.handlePickDirectoryMode(msg)
	case ModeConfirmRemoveFolder:
		return m.handleConfirmRemoveFolderMode(msg)
	case ModeCloneChoice:
		return m.handleCloneChoiceMode(msg)
	case ModeCloneRepo:
		return m.handleCloneRepoMode(msg)
	case ModeCloneURL:
		return m.handleCloneURLMode(msg)
	case ModeBookmarks:
		return m.handleBookmarksMode(msg)
	}
	return m, nil
}

// extractSessionName extracts a session name from a full path
// Uses the last N path components based on ProjectDepth config
func (m *Model) extractSessionName(fullPath string) string {
	parts := strings.Split(fullPath, string(filepath.Separator))
	depth := m.config.ProjectDepth
	if depth > len(parts) {
		depth = len(parts)
	}
	relPath := strings.Join(parts[len(parts)-depth:], "/")
	return sanitizeSessionName(relPath)
}

// extractDisplayPath extracts a display path from a full path
// Uses the last N path components based on ProjectDepth config
func (m *Model) extractDisplayPath(fullPath string) string {
	parts := strings.Split(fullPath, string(filepath.Separator))
	depth := m.config.ProjectDepth
	if depth > len(parts) {
		depth = len(parts)
	}
	return strings.Join(parts[len(parts)-depth:], "/")
}

// allSessions returns self session + other sessions as a combined slice
func (m *Model) allSessions() []tmux.Session {
	var all []tmux.Session
	if m.selfSession != nil {
		all = append(all, *m.selfSession)
	}
	all = append(all, m.sessions...)
	return all
}

// getSession returns the session for a given item (handles self session)
func (m *Model) getSession(item Item) *tmux.Session {
	if item.IsSelf {
		return m.selfSession
	}
	return &m.sessions[item.SessionIndex]
}

// findSessionByName finds a session by its name, returns nil if not found
func (m *Model) findSessionByName(name string) *tmux.Session {
	for i := range m.sessions {
		if m.sessions[i].Name == name {
			return &m.sessions[i]
		}
	}
	return nil
}

func (m *Model) applyLayout(sessionName, workingDir string) {
	if !m.config.EnableLayouts || m.config.Layout == "" {
		return
	}

	scriptPath := fmt.Sprintf("%s/%s.sh", m.config.LayoutDir, m.config.Layout)
	if _, err := os.Stat(scriptPath); err != nil {
		return
	}

	// Run layout script synchronously before switching to the session
	cmd := exec.Command(scriptPath, sessionName, workingDir)
	cmd.Env = append(os.Environ(),
		"TMUX_SESSION="+sessionName,
		"TMUX_WORKING_DIR="+workingDir,
	)
	_ = cmd.Run()
}

func (m *Model) loadClaudeStatuses() {
	m.claudeStatuses = make(map[string]claude.Status)
	if !m.config.ClaudeStatusEnabled {
		return
	}
	if m.selfSession != nil {
		status := claude.GetStatus(m.selfSession.Name, m.config.CacheDir)
		if status.State != "" {
			m.claudeStatuses[m.selfSession.Name] = status
		}
	}
	for _, s := range m.sessions {
		status := claude.GetStatus(s.Name, m.config.CacheDir)
		if status.State != "" {
			m.claudeStatuses[s.Name] = status
		}
	}
}

func (m *Model) loadPiStatuses() {
	m.piStatuses = make(map[string]pi.Status)
	if !m.config.PiStatusEnabled {
		return
	}
	if m.selfSession != nil {
		status := pi.GetStatus(m.selfSession.Name, m.config.CacheDir)
		if status.State != "" {
			m.piStatuses[m.selfSession.Name] = status
		}
	}
	for _, s := range m.sessions {
		status := pi.GetStatus(s.Name, m.config.CacheDir)
		if status.State != "" {
			m.piStatuses[s.Name] = status
		}
	}
}

// fetchGitStatusesCmd returns commands that fetch git statuses in parallel
// Each session's status is fetched independently and updates the UI as soon as ready
func (m *Model) fetchGitStatusesCmd() tea.Cmd {
	allSessions := m.allSessions()
	if !m.config.GitStatusEnabled || len(allSessions) == 0 {
		return nil
	}

	// Track which sessions we're waiting for
	m.gitStatusPending = make(map[string]bool)
	m.gitStatusShowLoading = false
	for _, s := range allSessions {
		m.gitStatusPending[s.Name] = true
	}

	// Create a command for each session - they run in parallel via tea.Batch
	cmds := make([]tea.Cmd, 0, len(allSessions)+1)

	// Add delayed loading indicator (500ms)
	cmds = append(cmds, tea.Tick(500*time.Millisecond, func(time.Time) tea.Msg {
		return gitStatusLoadingMsg{}
	}))

	for _, s := range allSessions {
		sessionName := s.Name // capture for closure
		cmds = append(cmds, func() tea.Msg {
			path, err := git.GetSessionPath(sessionName)
			if err != nil || path == "" {
				return gitStatusSingleMsg{sessionName: sessionName, hasStatus: false}
			}
			status := git.GetStatus(path)
			if status.IsRepo && !status.IsClean() {
				return gitStatusSingleMsg{sessionName: sessionName, status: status, hasStatus: true}
			}
			return gitStatusSingleMsg{sessionName: sessionName, hasStatus: false}
		})
	}

	return tea.Batch(cmds...)
}

func (m *Model) calculateColumnWidths() {
	// Don't reset - preserve cached width to prevent layout shift
	if m.selfSession != nil {
		if len(m.selfSession.Name) > m.maxNameWidth {
			m.maxNameWidth = len(m.selfSession.Name)
		}
	}
	for _, s := range m.sessions {
		if len(s.Name) > m.maxNameWidth {
			m.maxNameWidth = len(s.Name)
		}
	}
}

// stateText returns the state line text based on current mode and context.
// Now only used by the STATUS sidebar section — no longer in footer.
// Kept for potential future use.
//
//nolint:unused
func (m *Model) stateText() string {
	switch m.mode {
	case ModeNormal:
		total := len(m.sessions)
		if m.selfSession != nil {
			total++
		}
		visible := len(m.items)
		if m.filter != "" {
			return fmt.Sprintf("Showing %d/%d sessions", visible, total)
		}
		return fmt.Sprintf("%d sessions", total)
	case ModeBookmarks:
		total := len(m.config.Bookmarks)
		if total == 0 {
			return "No bookmarks"
		}
		return fmt.Sprintf("%d bookmarks", total)
	case ModePickDirectory:
		if m.pendingSessionName != "" {
			return fmt.Sprintf("Select location for: %s", m.pendingSessionName)
		}
		total := len(m.projectList.Items())
		visible := m.projectList.Len()
		if m.projectList.Filter() != "" {
			return fmt.Sprintf("Showing %d/%d projects", visible, total)
		}
		return fmt.Sprintf("%d projects", total)
	case ModeCloneChoice:
		return "Clone repository"
	case ModeCloneURL:
		if m.cloneSuccess {
			return "Clone successful"
		}
		if m.cloneCloning {
			return fmt.Sprintf("Cloning %s...", m.cloneCloningRepo)
		}
		return "Enter repo URL"
	case ModeCloneRepo:
		if m.cloneSuccess {
			return "Clone successful"
		}
		if m.cloneLoading {
			return "Loading repositories..."
		}
		if m.cloneCloning {
			return fmt.Sprintf("Cloning %s...", m.cloneCloningRepo)
		}
		total := len(m.cloneList.Items())
		visible := m.cloneList.Len()
		if m.cloneList.Filter() != "" {
			return fmt.Sprintf("Showing %d/%d repositories", visible, total)
		}
		return fmt.Sprintf("%d repositories", total)
	case ModeCreate:
		return "Enter session name"
	case ModeConfirmKill:
		return fmt.Sprintf("Kill session: %s?", m.killTarget)
	case ModeConfirmRemoveFolder:
		return fmt.Sprintf("Remove folder: %s?", filepath.Base(m.removeTarget))
	default:
		return ""
	}
}

func (m *Model) rebuildItems() {
	m.items = nil
	filterLower := strings.ToLower(m.filter)

	// Pin self session at top (always visible, not affected by filter)
	if m.selfSession != nil {
		m.items = append(m.items, Item{
			Type:   ItemTypeSession,
			IsSelf: true,
		})

		if m.selfSession.Expanded {
			for j, window := range m.selfSession.Windows {
				m.items = append(m.items, Item{
					Type:        ItemTypeWindow,
					IsSelf:      true,
					WindowIndex: j,
				})

				if window.Expanded {
					for k := range window.Panes {
						m.items = append(m.items, Item{
							Type:        ItemTypePane,
							IsSelf:      true,
							WindowIndex: j,
							PaneIndex:   k,
						})
					}
				}
			}
		}
	}

	for i, session := range m.sessions {
		// Apply fuzzy filter if active
		if m.filter != "" && !fuzzy.Match(session.Name, filterLower) {
			continue
		}

		m.items = append(m.items, Item{
			Type:         ItemTypeSession,
			SessionIndex: i,
		})

		if session.Expanded {
			for j, window := range session.Windows {
				m.items = append(m.items, Item{
					Type:         ItemTypeWindow,
					SessionIndex: i,
					WindowIndex:  j,
				})

				// Add panes if window is expanded
				if window.Expanded {
					for k := range window.Panes {
						m.items = append(m.items, Item{
							Type:         ItemTypePane,
							SessionIndex: i,
							WindowIndex:  j,
							PaneIndex:    k,
						})
					}
				}
			}
		}
	}

	// Ensure cursor is in bounds
	if m.cursor >= len(m.items) {
		m.cursor = len(m.items) - 1
	}
	if m.cursor < 0 {
		m.cursor = 0
	}
	m.updateScrollOffset()
}

// updateScrollOffset adjusts scroll offset to keep cursor visible in session list
func (m *Model) updateScrollOffset() {
	maxVisible := m.sessionMaxVisibleItems()
	// If cursor is above visible area, scroll up
	if m.cursor < m.scrollOffset {
		m.scrollOffset = m.cursor
	}
	// If cursor is below visible area, scroll down
	if m.cursor >= m.scrollOffset+maxVisible {
		m.scrollOffset = m.cursor - maxVisible + 1
	}
	// Ensure scroll offset is not negative
	if m.scrollOffset < 0 {
		m.scrollOffset = 0
	}
}

// contentWidth returns the available width inside the app border/padding
func (m *Model) contentWidth() int {
	if m.width > 0 {
		return m.width - ui.AppBorderOverheadX
	}
	return 56 // Default fallback (60 - 4)
}

// contentHeight returns the available height inside the app border/padding
func (m *Model) contentHeight() int {
	if m.height > 0 {
		return m.height - ui.AppBorderOverheadY
	}
	return 0
}

// borderWidth returns the width to use for internal borders
func (m *Model) borderWidth() int {
	return m.contentWidth()
}

// sessionListWidth returns the width available for the session list.
// Now equivalent to contentWidth — actions moved to bottom bar.
func (m *Model) sessionListWidth() int {
	return m.contentWidth()
}

// rowWidth returns the width available for row content (accounts for scrollbar column).
func (m *Model) rowWidth() int {
	return m.contentWidth() - ui.ScrollbarColumnWidth
}

// statusLine returns a compact status string for the footer
func (m *Model) statusLine() string {
	total := len(m.sessions)
	if m.selfSession != nil {
		total++
	}
	return fmt.Sprintf("%d sessions", total)
}

// renderWithSidebar composes list content with a bottom action bar and simplified footer.
// listContent is the session/bookmark/project list string.
// actions is the mode-specific action set for the bottom bar.
// notification is the message to show in the footer.
// hints is a single-line keybind hint string.
// isError indicates notification is an error.
func (m *Model) renderWithSidebar(header, listContent string, actions []ui.Action, notification, hints string, isError bool) string {
	var b strings.Builder

	// Header (full width)
	b.WriteString(header)

	// List content (full width — no sidebar)
	b.WriteString(listContent)

	// Count content lines so far (header + list)
	content := b.String()
	contentLineCount := strings.Count(content, "\n")

	// Pad to push footer to bottom: target = contentHeight - dotted line - action bar - footer lines
	targetContentLines := m.contentHeight() - ui.ActionBarHeight - 5
	if targetContentLines > contentLineCount {
		padding := targetContentLines - contentLineCount
		for i := 0; i < padding; i++ {
			b.WriteString("\n")
		}
	}

	// Dotted separator above action bar
	b.WriteString(ui.RenderDottedBorder(m.contentWidth()))
	b.WriteString("\n")

	// Bottom action bar (2 rows of buttons)
	b.WriteString(ui.RenderButtonBar(actions, m.contentWidth()))
	b.WriteString("\n")

	// Footer at the very bottom
	b.WriteString(ui.RenderSimpleFooter(notification, hints, isError, m.width))

	return ui.AppStyle.Height(m.contentHeight()).Render(b.String())
}

// isCursorValid returns true if cursor points to a valid item
func (m *Model) isCursorValid() bool {
	return m.cursor >= 0 && m.cursor < len(m.items)
}

// getTargetName returns the tmux target name for the given item
func (m *Model) getTargetName(item Item) string {
	session := m.getSession(item)
	switch item.Type {
	case ItemTypeSession:
		return session.Name
	case ItemTypeWindow:
		window := session.Windows[item.WindowIndex]
		return fmt.Sprintf("%s:%d", session.Name, window.Index)
	case ItemTypePane:
		window := session.Windows[item.WindowIndex]
		pane := window.Panes[item.PaneIndex]
		return fmt.Sprintf("%s:%d.%d", session.Name, window.Index, pane.Index)
	default:
		return session.Name
	}
}

// setError sets an error message on the model
func (m *Model) setError(format string, args ...any) {
	m.message = fmt.Sprintf(format, args...)
	m.messageIsError = true
}

// setMessage sets a non-error message on the model
func (m *Model) setMessage(format string, args ...any) {
	m.message = fmt.Sprintf(format, args...)
	m.messageIsError = false
}

// sanitizeSessionName converts a path to a valid tmux session name
// Dots and colons have special meaning in tmux target syntax (window.pane, session:window)
// Spaces cause issues with shell commands
func sanitizeSessionName(name string) string {
	replacer := strings.NewReplacer(
		"/", "-",
		".", "-",
		":", "-",
		" ", "-",
	)
	return replacer.Replace(name)
}

// View implements tea.Model
func (m Model) View() string {
	if m.mode == ModePickDirectory || m.mode == ModeConfirmRemoveFolder {
		return m.viewPickDirectory()
	}
	if m.mode == ModeCloneChoice {
		return m.viewCloneChoice()
	}
	if m.mode == ModeCloneRepo {
		return m.viewCloneRepo()
	}
	if m.mode == ModeCloneURL {
		return m.viewCloneURL()
	}
	if m.mode == ModeBookmarks {
		return m.viewBookmarks()
	}
	if m.mode == ModeCreatePath {
		return m.viewCreatePath()
	}
	return m.viewSessionList()
}

// sessionCachePath returns the path to the session cache file
func (m *Model) sessionCachePath() string {
	return filepath.Join(m.config.CacheDir, "sessions.json")
}

// cachedSession is a simplified session for caching (excludes UI state)
type cachedSession struct {
	Name         string    `json:"name"`
	LastActivity time.Time `json:"last_activity"`
}

// sessionCache wraps cached sessions with layout metadata for stable column widths
type sessionCache struct {
	Sessions     []cachedSession `json:"sessions"`
	MaxNameWidth int             `json:"max_name_width"` // Persisted to prevent layout shift
}

// loadSessionCache loads cached sessions from disk
// Returns nil if cache doesn't exist or is invalid
func (m *Model) loadSessionCache() []tmux.Session {
	data, err := os.ReadFile(m.sessionCachePath())
	if err != nil {
		return nil
	}

	// Try new format first (with layout metadata)
	var cache sessionCache
	if err := json.Unmarshal(data, &cache); err == nil && len(cache.Sessions) > 0 {
		m.maxNameWidth = cache.MaxNameWidth
		sessions := make([]tmux.Session, len(cache.Sessions))
		for i, c := range cache.Sessions {
			sessions[i] = tmux.Session{
				Name:         c.Name,
				LastActivity: c.LastActivity,
			}
		}
		return sessions
	}

	// Fallback: try old format (array of sessions) for backwards compatibility
	var cached []cachedSession
	if err := json.Unmarshal(data, &cached); err != nil {
		return nil
	}

	sessions := make([]tmux.Session, len(cached))
	for i, c := range cached {
		sessions[i] = tmux.Session{
			Name:         c.Name,
			LastActivity: c.LastActivity,
		}
	}
	return sessions
}

// saveSessionCache saves sessions to disk for instant startup
func (m *Model) saveSessionCache() {
	cached := make([]cachedSession, len(m.sessions))
	for i, s := range m.sessions {
		cached[i] = cachedSession{
			Name:         s.Name,
			LastActivity: s.LastActivity,
		}
	}

	cache := sessionCache{
		Sessions:     cached,
		MaxNameWidth: m.maxNameWidth,
	}

	data, err := json.Marshal(cache)
	if err != nil {
		return
	}

	// Ensure cache directory exists
	if err := os.MkdirAll(m.config.CacheDir, 0755); err != nil {
		return
	}

	_ = os.WriteFile(m.sessionCachePath(), data, 0644)
}

package ui

import "strings"

// ScrollList is a generic scrollable list with cursor, filtering, and scroll offset management.
// It eliminates duplicate scroll/cursor logic across different list modes.
type ScrollList[T any] struct {
	items        []T
	filtered     []T
	cursor       int
	scrollOffset int
	filter       string
	filterFn     func(T, string) bool // Returns true if item matches filter
	height       int                  // Visible height (number of items that fit)
}

// NewScrollList creates a new ScrollList with a filter function.
// The filterFn should return true if the item matches the given filter string.
func NewScrollList[T any](filterFn func(T, string) bool) *ScrollList[T] {
	return &ScrollList[T]{
		filterFn: filterFn,
		height:   10, // Default fallback
	}
}

// SetItems replaces all items and re-applies the current filter
func (s *ScrollList[T]) SetItems(items []T) {
	s.items = items
	s.applyFilter()
}

// SetHeight sets the visible height (number of items that fit on screen)
func (s *ScrollList[T]) SetHeight(height int) {
	if height > 0 {
		s.height = height
	}
	s.updateScrollOffset()
}

// Height returns the current visible height
func (s *ScrollList[T]) Height() int {
	return s.height
}

// SetFilter sets the filter text and re-filters the items
func (s *ScrollList[T]) SetFilter(filter string) {
	s.filter = filter
	s.applyFilter()
}

// Filter returns the current filter string
func (s *ScrollList[T]) Filter() string {
	return s.filter
}

// applyFilter applies the current filter to items
func (s *ScrollList[T]) applyFilter() {
	if s.filter == "" {
		s.filtered = s.items
	} else {
		s.filtered = nil
		filterLower := strings.ToLower(s.filter)
		for _, item := range s.items {
			if s.filterFn(item, filterLower) {
				s.filtered = append(s.filtered, item)
			}
		}
	}
	s.clampCursor()
	s.updateScrollOffset()
}

// Items returns all items (unfiltered)
func (s *ScrollList[T]) Items() []T {
	return s.items
}

// Filtered returns the filtered items
func (s *ScrollList[T]) Filtered() []T {
	return s.filtered
}

// Len returns the number of filtered items
func (s *ScrollList[T]) Len() int {
	return len(s.filtered)
}

// Cursor returns the current cursor position
func (s *ScrollList[T]) Cursor() int {
	return s.cursor
}

// SetCursor sets the cursor position and updates scroll offset
func (s *ScrollList[T]) SetCursor(pos int) {
	s.cursor = pos
	s.clampCursor()
	s.updateScrollOffset()
}

// MoveCursor moves the cursor by delta and updates scroll offset
func (s *ScrollList[T]) MoveCursor(delta int) {
	s.cursor += delta
	s.clampCursor()
	s.updateScrollOffset()
}

// clampCursor ensures cursor is within valid bounds
func (s *ScrollList[T]) clampCursor() {
	if s.cursor >= len(s.filtered) {
		s.cursor = len(s.filtered) - 1
	}
	if s.cursor < 0 {
		s.cursor = 0
	}
}

// ScrollOffset returns the current scroll offset
func (s *ScrollList[T]) ScrollOffset() int {
	return s.scrollOffset
}

// updateScrollOffset adjusts scroll offset to keep cursor visible
func (s *ScrollList[T]) updateScrollOffset() {
	// If cursor is above visible area, scroll up
	if s.cursor < s.scrollOffset {
		s.scrollOffset = s.cursor
	}
	// If cursor is below visible area, scroll down
	if s.cursor >= s.scrollOffset+s.height {
		s.scrollOffset = s.cursor - s.height + 1
	}
	// Ensure scroll offset is not negative
	if s.scrollOffset < 0 {
		s.scrollOffset = 0
	}
}

// SelectedItem returns the currently selected item, or false if none
func (s *ScrollList[T]) SelectedItem() (T, bool) {
	var zero T
	if s.cursor < 0 || s.cursor >= len(s.filtered) {
		return zero, false
	}
	return s.filtered[s.cursor], true
}

// VisibleItems returns the slice of items currently visible on screen
func (s *ScrollList[T]) VisibleItems() []T {
	if len(s.filtered) == 0 {
		return nil
	}

	start := s.scrollOffset
	end := start + s.height
	if end > len(s.filtered) {
		end = len(s.filtered)
	}
	if start >= end {
		return nil
	}
	return s.filtered[start:end]
}

// VisibleRange returns the start and end indices of visible items in the filtered slice
func (s *ScrollList[T]) VisibleRange() (start, end int) {
	start = s.scrollOffset
	end = start + s.height
	if end > len(s.filtered) {
		end = len(s.filtered)
	}
	return start, end
}

// IsSelected returns true if the given index (in filtered list) is the cursor position
func (s *ScrollList[T]) IsSelected(index int) bool {
	return index == s.cursor
}

// Reset clears the filter and resets cursor to 0
func (s *ScrollList[T]) Reset() {
	s.filter = ""
	s.cursor = 0
	s.scrollOffset = 0
	s.applyFilter()
}

// Clear removes all items
func (s *ScrollList[T]) Clear() {
	s.items = nil
	s.filtered = nil
	s.cursor = 0
	s.scrollOffset = 0
	s.filter = ""
}

package ui

import (
	"fmt"
	"strings"
	"time"

	"github.com/charmbracelet/lipgloss"

	"github.com/black-atom-industries/helm/internal/claude"
	"github.com/black-atom-industries/helm/internal/git"
	"github.com/black-atom-industries/helm/internal/pi"
)

// RowLayout holds calculated column widths for consistent alignment across rows
type RowLayout struct {
	NameWidth      int
	GitStatusWidth int
}

// RowOpts contains options for rendering a generic row
// Required: Num, Name, Selected
// Optional: all others (use zero values to omit)
type RowOpts struct {
	// Required
	Num      int
	Name     string
	Selected bool

	// Optional - set to enable
	ShowExpandIcon   bool           // Show ▸/▾ expand indicator
	Expanded         bool           // Expansion state
	LastActivity     *time.Time     // Show time ago if set
	GitStatus        *git.Status    // Show git status if set
	GitStatusLoading bool           // Show loading indicator for git status
	ClaudeStatus     *claude.Status // Show claude status if set
	PiStatus         *pi.Status     // Show pi status if set
	AnimFrame        int            // Animation frame for status icons
	IsSelf           bool           // True for the pinned current/self session
}

// WindowRowOpts contains per-row options for rendering a window
type WindowRowOpts struct {
	Selected bool
	Expanded bool // Window is expanded to show panes
}

// PaneRowOpts contains per-row options for rendering a pane
type PaneRowOpts struct {
	Selected bool
}

// Column component functions - each returns a styled string

// SpacerStyle returns a spacer with background when selected
func SpacerStyle(text string, selected bool) string {
	if selected {
		return lipgloss.NewStyle().Background(Colors.Bg.Selected).Render(text)
	}
	return text
}

// RenderIndex renders the session number (1-9)
func RenderIndex(num int, selected bool) string {
	label := fmt.Sprintf("%d", num)
	if selected {
		return IndexSelectedStyle.Render(label)
	}
	return IndexStyle.Render(label)
}

// RenderExpandIcon renders the expand/collapse indicator
func RenderExpandIcon(expanded, selected bool) string {
	if expanded {
		if selected {
			return ExpandedIconSelected
		}
		return ExpandedIcon
	}
	if selected {
		return CollapsedIconSelected
	}
	return CollapsedIcon
}

// RenderName renders a name with padding to a fixed width
func RenderName(name string, width int, selected bool, selectedStyle, defaultStyle lipgloss.Style) string {
	padded := fmt.Sprintf("%-*s", width, name)
	if selected {
		return selectedStyle.Render(padded)
	}
	return defaultStyle.Render(padded)
}

// RenderSessionName renders the session name
func RenderSessionName(name string, width int, selected bool) string {
	return RenderName(name, width, selected, SessionNameSelectedStyle, SessionNameStyle)
}

// RenderWindowName renders the window name with index
func RenderWindowName(index int, name string, selected bool) string {
	text := fmt.Sprintf("%d: %s", index, name)
	if selected {
		return WindowNameSelectedStyle.Render(text)
	}
	return WindowNameStyle.Render(text)
}

// RenderTimeAgo renders the time since last activity
func RenderTimeAgo(t time.Time, selected bool) string {
	timeAgo := FormatTimeAgo(t)
	padded := fmt.Sprintf("%-8s", timeAgo)
	if selected {
		return TimeSelectedStyle.Render(padded)
	}
	return TimeStyle.Render(padded)
}

// FormatTimeAgo formats a time as a human-readable "X ago" string
func FormatTimeAgo(t time.Time) string {
	d := time.Since(t)

	if d < time.Minute {
		return fmt.Sprintf("%ds ago", int(d.Seconds()))
	}
	if d < time.Hour {
		return fmt.Sprintf("%dm ago", int(d.Minutes()))
	}
	if d < 24*time.Hour {
		return fmt.Sprintf("%dh ago", int(d.Hours()))
	}
	return fmt.Sprintf("%dd ago", int(d.Hours()/24))
}

// RenderGitStatusColumn renders the git status with padding to a fixed width
func RenderGitStatusColumn(status *git.Status, maxWidth int, selected bool, loading bool, animFrame int) string {
	if maxWidth == 0 {
		return ""
	}

	// Show spinner if still fetching
	if loading {
		frame := animFrame % len(ClaudeSpinnerFrames)
		spinner := GitLoadingStyle.Render(ClaudeSpinnerFrames[frame])
		if maxWidth > 1 {
			padding := SpacerStyle(strings.Repeat(" ", maxWidth-1), selected)
			return spinner + padding
		}
		return spinner
	}

	if status == nil {
		return SpacerStyle(strings.Repeat(" ", maxWidth), selected)
	}

	formatted := FormatGitStatus(status.Dirty, status.Additions, status.Deletions, selected)
	actualWidth := GitStatusWidth(status.Dirty, status.Additions, status.Deletions)

	if actualWidth < maxWidth {
		padding := SpacerStyle(strings.Repeat(" ", maxWidth-actualWidth), selected)
		return formatted + padding
	}
	return formatted
}

// RenderClaudeIcon renders a single-character Claude status icon
// Returns a space for no status to preserve column alignment
func RenderClaudeIcon(status *claude.Status, animFrame int, selected bool) string {
	if status == nil || status.State == "" {
		return SpacerStyle(" ", selected) // Reserved space for alignment
	}
	waitDuration := time.Since(status.Timestamp)
	icon := FormatClaudeIcon(status.State, animFrame, waitDuration)
	if selected {
		// Re-apply the icon style with background
		return lipgloss.NewStyle().Background(Colors.Bg.Selected).Render(icon)
	}
	return icon
}

// RenderPiIcon renders a single-character Pi status icon
// Returns a space for no status to preserve column alignment
func RenderPiIcon(status *pi.Status, animFrame int, selected bool) string {
	if status == nil || status.State == "" {
		return SpacerStyle(" ", selected) // Reserved space for alignment
	}
	waitDuration := time.Since(status.Timestamp)
	icon := FormatPiIcon(status.State, animFrame, waitDuration)
	if selected {
		// Re-apply the icon style with background
		return lipgloss.NewStyle().Background(Colors.Bg.Selected).Render(icon)
	}
	return icon
}

// SessionRowOpts wraps RowOpts with session-specific settings
type SessionRowOpts struct {
	RowOpts
}

// RenderSelfIndex renders the self-session marker instead of a number
func RenderSelfIndex(selected bool) string {
	if selected {
		return SelfIndexSelectedStyle.Render("*")
	}
	return SelfIndexStyle.Render("*")
}

// RenderSelfSessionName renders the self-session name
func RenderSelfSessionName(name string, width int, selected bool) string {
	padded := fmt.Sprintf("%-*s", width, name)
	if selected {
		return SelfNameSelectedStyle.Render(padded)
	}
	return SelfNameStyle.Render(padded)
}

// RenderSessionRow composes all columns into a complete session row
func RenderSessionRow(name string, lastActivity time.Time, layout RowLayout, opts SessionRowOpts, width int) string {
	// Self session uses distinct index marker and name style
	renderIndex := RenderIndex(opts.Num, opts.Selected)
	renderName := RenderSessionName(name, layout.NameWidth, opts.Selected)
	if opts.IsSelf {
		renderIndex = RenderSelfIndex(opts.Selected)
		renderName = RenderSelfSessionName(name, layout.NameWidth, opts.Selected)
	}

	cols := []string{
		renderIndex,
		SpacerStyle(" ", opts.Selected),
	}

	// Status columns: always show both CC and Pi together (reserved space for alignment).
	// Spacer between icons is 2 chars wide to align under the 2-char "CC"/"Pi" headers.
	cols = append(cols,
		RenderClaudeIcon(opts.ClaudeStatus, opts.AnimFrame, opts.Selected),
		SpacerStyle("  ", opts.Selected),
		RenderPiIcon(opts.PiStatus, opts.AnimFrame, opts.Selected),
		SpacerStyle(" ", opts.Selected),
	)

	// Expand icon (optional)
	if opts.ShowExpandIcon {
		cols = append(cols, RenderExpandIcon(opts.Expanded, opts.Selected), SpacerStyle(" ", opts.Selected))
	}

	// Name (always shown)
	cols = append(cols, renderName)

	// Time ago (optional)
	if opts.LastActivity != nil {
		cols = append(cols, SpacerStyle("  ", opts.Selected), RenderTimeAgo(*opts.LastActivity, opts.Selected))
	}

	// Git status (optional column)
	if layout.GitStatusWidth > 0 {
		cols = append(cols, SpacerStyle(" ", opts.Selected), RenderGitStatusColumn(opts.GitStatus, layout.GitStatusWidth, opts.Selected, opts.GitStatusLoading, opts.AnimFrame))
	}

	content := strings.Join(cols, "")
	if opts.Selected {
		return SessionSelectedStyle.Width(width).Render(content)
	}
	return SessionStyle.Width(width).Render(content)
}

// RenderBookmarkRow composes a bookmark row (simpler than session row)
func RenderBookmarkRow(name string, layout RowLayout, opts RowOpts, width int) string {
	cols := []string{
		RenderIndex(opts.Num, opts.Selected),
		SpacerStyle(" ", opts.Selected),
		// Status columns: always show both CC and Pi together (reserved space for alignment).
		// Spacer between icons is 2 chars wide to align under the 2-char "CC"/"Pi" headers.
		RenderClaudeIcon(opts.ClaudeStatus, opts.AnimFrame, opts.Selected),
		SpacerStyle("  ", opts.Selected),
		RenderPiIcon(opts.PiStatus, opts.AnimFrame, opts.Selected),
		SpacerStyle(" ", opts.Selected),
		RenderSessionName(name, layout.NameWidth, opts.Selected),
	}

	// Git status (optional)
	if layout.GitStatusWidth > 0 {
		cols = append(cols, SpacerStyle(" ", opts.Selected), RenderGitStatusColumn(opts.GitStatus, layout.GitStatusWidth, opts.Selected, opts.GitStatusLoading, opts.AnimFrame))
	}

	content := strings.Join(cols, "")
	if opts.Selected {
		return SessionSelectedStyle.Width(width).Render(content)
	}
	return SessionStyle.Width(width).Render(content)
}

// TableHeaderOpts controls which columns appear in the header
type TableHeaderOpts struct {
	ShowExpandIcon bool
	ShowTime       bool
	ShowGit        bool
	ShowCC         bool   // Show Claude Code status column
	ShowPi         bool   // Show Pi status column
	NameLabel      string // e.g., "Session" or "Bookmark"
}

// RenderTableHeader renders a header row above the content list
func RenderTableHeader(layout RowLayout, opts TableHeaderOpts) string {
	dim := TableHeaderTextStyle // shorthand for dim text

	cols := []string{
		"  ", // Align with scrollbar column in data rows
		dim.Render(fmt.Sprintf("%-3s", "#")),
	}

	// Status columns: show which ones are enabled (data rows always reserve both)
	if opts.ShowCC {
		cols = append(cols, " ", CCHeaderStyle.Render("CC"))
	}
	if opts.ShowPi {
		cols = append(cols, " ", PiHeaderStyle.Render("Pi"))
	}

	// Expand icon placeholder
	if opts.ShowExpandIcon {
		cols = append(cols, " ", " ")
	}

	// Name column header
	nameLabel := opts.NameLabel
	if nameLabel == "" {
		nameLabel = "NAME"
	}
	cols = append(cols, dim.Render(fmt.Sprintf("%-*s", layout.NameWidth, nameLabel)))

	// Time column header
	if opts.ShowTime {
		cols = append(cols, "  ", dim.Render(fmt.Sprintf("%-8s", "ACT")))
	}

	// Git column header
	if opts.ShowGit && layout.GitStatusWidth > 0 {
		cols = append(cols, " ", dim.Render(fmt.Sprintf("%-*s", layout.GitStatusWidth, "GIT")))
	}

	content := strings.Join(cols, "")
	return TableHeaderStyle.Render(content)
}

// RenderWindowRow composes a window row
func RenderWindowRow(index int, name string, opts WindowRowOpts, width int) string {
	var parts []string

	// Expand icon for windows (shows if window can be expanded to show panes)
	parts = append(parts, RenderExpandIcon(opts.Expanded, opts.Selected))
	parts = append(parts, SpacerStyle(" ", opts.Selected))

	// Window name with index
	parts = append(parts, RenderWindowName(index, name, opts.Selected))

	content := strings.Join(parts, "")
	if opts.Selected {
		return WindowSelectedStyle.Width(width).Render(content)
	}
	return WindowStyle.Width(width).Render(content)
}

// RenderPaneRow composes a pane row
// Panes are indented further than windows
func RenderPaneRow(index int, command string, active bool, opts PaneRowOpts, width int) string {
	// Format: "index: command" with "*" for active pane
	activeMarker := " "
	if active {
		activeMarker = "*"
	}
	text := fmt.Sprintf("%s %d: %s", activeMarker, index, command)

	if opts.Selected {
		return PaneSelectedStyle.Width(width).Render(text)
	}
	return PaneStyle.Width(width).Render(text)
}

// ItemDepth represents the hierarchy level of an item
// This design allows easy extension for panes (helm-xdn)
type ItemDepth int

const (
	DepthSession ItemDepth = 0
	DepthWindow  ItemDepth = 1
	DepthPane    ItemDepth = 2 // Future use
)

// IndentForDepth returns the left padding for a given depth level
func IndentForDepth(depth ItemDepth) int {
	switch depth {
	case DepthSession:
		return 0
	case DepthWindow:
		return 10 // Matches current WindowStyle.PaddingLeft
	case DepthPane:
		return 14 // Further indented for panes
	default:
		return 0
	}
}

