			height: 0,
			want:   10,
		},
		{
			name:   "small window",
			height: 12, // contentHeight = 10, overhead = 6 + 5 = 11, available = -1 → fallback
			want:   10,
		},
		{
			name:   "large window uses all space",
			height: 50, // contentHeight = 48, overhead = 11, available = 37
			want:   37,
		},
		{
			name:   "medium window",
			height: 17, // contentHeight = 15, overhead = 11, available = 4
			want:   4,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			cfg := config.DefaultConfig()
			m := Model{
				height: tt.height,
				config: cfg,
			}
			got := m.projectMaxVisibleItems()
			if got != tt.want {
				t.Errorf("projectMaxVisibleItems() with height=%d = %d, want %d",
					tt.height, got, tt.want)
			}
		})
	}
}

